parameters.jsCode:
const seenSeasons = new Set();
const uniqueItems = [];

for (const item of $input.all()) {
  const key = `${item.json.seriesId}-${item.json.seasonNumber}`;

  if (!seenSeasons.has(key)) {
    item.json.myNewField = 1;
    uniqueItems.push(item);
    seenSeasons.add(key);
  }
}

uniqueItems.sort((a, b) => {
  if (a.json.seriesId !== b.json.seriesId) {
    return a.json.seriesId - b.json.seriesId;
  }
  return a.json.seasonNumber - b.json.seasonNumber;
});

return uniqueItems;
